SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, ts_aggr.timestamp AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption", sum(ts_aggr."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption" FROM (SELECT ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, sum(ts_flat."_v__out.electricity.total.energy_consumption") AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") AS "bs__out.natural_gas.total.energy_consumption", count(*) AS _inner_rows FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, date_trunc('month', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption", resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS "_v__out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (1) AND resstock_2024_amy2018_release_2_by_state_vu.state IN ('CO', 'WY')) AS ts_flat GROUP BY ts_flat.timestamp, ts_flat.bldg_id) AS ts_aggr JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_aggr.bldg_id AND bs.upgrade = 0 GROUP BY 1, 2 ORDER BY 1, 2